    pinnedAppIds: string[];
    setPinnedAppIds: (ids: string[] | ((val: string[]) => string[])) => void;
    allApps: AppDefinition[];
    onOpenApp: (appId: string, e?: React.MouseEvent<HTMLButtonElement>) => void;
